### 2. WebSocket Channel Configuration

```typescript
// apps/gateway/src/ws/channels.ts

export const RU_CHANNELS = {
  // Fleet-wide updates (repo add/remove/status)
  FLEET: { kind: "fleet", scope: "repos" },

  // Sync operation updates
  SYNC: { kind: "fleet", scope: "sync" },

  // Specific sync session
  SYNC_SESSION: (sessionId: string) => ({
    kind: "fleet",
    scope: `sync:${sessionId}`,
  }),

  // Sweep updates
  SWEEP: { kind: "fleet", scope: "sweep" },

  // Specific sweep session
  SWEEP_SESSION: (sessionId: string) => ({
    kind: "fleet",
    scope: `sweep:${sessionId}`,
  }),
};

// Event routing helper
export function getChannelForEvent(event: RUEvent): Channel {
  switch (event.type) {
    case "ru.repo_added":
    case "ru.repo_removed":
    case "ru.repo_status_changed":
      return RU_CHANNELS.FLEET;

    case "ru.sync_started":
    case "ru.sync_completed":
    case "ru.sync_cancelled":
      return RU_CHANNELS.SYNC;

    case "ru.sync_repo_started":
    case "ru.sync_repo_completed":
      return RU_CHANNELS.SYNC_SESSION(event.data.sessionId);

    case "ru.sweep_created":
    case "ru.sweep_started":
    case "ru.sweep_completed":
      return RU_CHANNELS.SWEEP;

    case "ru.sweep_progress":
    case "ru.sweep_phase_completed":
    case "ru.sweep_plan_created":
    case "ru.sweep_plan_approved":
    case "ru.sweep_plan_rejected":
      return RU_CHANNELS.SWEEP_SESSION(event.data.sessionId);

    default:
      return RU_CHANNELS.FLEET;
  }
}
```

### 3. Event Publisher Utility

```typescript
// apps/gateway/src/services/ru-events.ts

import { getHub } from "../ws/hub";
import { getChannelForEvent, RU_CHANNELS } from "../ws/channels";
import { logger } from "./logger";

export function publishRUEvent(event: RUEvent): void {
  const channel = getChannelForEvent(event);
  const eventWithTimestamp = {
    ...event,
    timestamp: event.timestamp || new Date().toISOString(),
  };

  getHub().publish(channel, eventWithTimestamp);

  logger.debug({
    eventType: event.type,
    channel,
    sessionId: event.data.sessionId,
  }, "Published RU event");
}

// Convenience publishers
export function publishRepoAdded(repo: FleetRepo): void {
  publishRUEvent({
    type: "ru.repo_added",
    data: {
      repoId: repo.id,
      fullName: repo.fullName,
      owner: repo.owner,
      name: repo.name,
    },
    timestamp: new Date().toISOString(),
  });
}

export function publishSyncProgress(
  sessionId: string,
  repoId: string,
  fullName: string,
  success: boolean,
  stats: { completed: number; failed: number; total: number }
): void {
  publishRUEvent({
    type: "ru.sync_repo_completed",
    data: {
      sessionId,
      repoId,
      fullName,
      success,
      duration: 0, // Set by caller
      ...stats,
    },
    timestamp: new Date().toISOString(),
  });
}

export function publishSweepProgress(
  sessionId: string,
  phase: "phase1" | "phase2" | "phase3",
  current: string,
  progress: Record<string, number>
): void {
  publishRUEvent({
    type: "ru.sweep_progress",
    data: {
      sessionId,
      phase,
      current,
      progress: { ...progress, total: progress.total || 0 },
    },
    timestamp: new Date().toISOString(),
  });
}
```

### 4. WebSocket Handler Updates

```typescript
// apps/gateway/src/ws/handler.ts

import { RU_CHANNELS } from "./channels";

// Add RU channel subscriptions to handler
export function handleSubscription(ws: WebSocket, message: SubscribeMessage): void {
  const { channel } = message;

  // Validate channel
  const validChannels = [
    "fleet:repos",
    "fleet:sync",
    "fleet:sweep",
    /^fleet:sync:[a-z0-9_]+$/,
    /^fleet:sweep:[a-z0-9_]+$/,
  ];

  const isValid = validChannels.some(pattern =>
    typeof pattern === "string"
      ? pattern === channel
      : pattern.test(channel)
  );

  if (!isValid) {
    ws.send(JSON.stringify({
      type: "error",
      error: "Invalid channel",
      channel,
    }));
    return;
  }

  // Subscribe
  const [kind, scope] = channel.split(":");
  getHub().subscribe(ws, { kind, scope });

  ws.send(JSON.stringify({
    type: "subscribed",
    channel,
  }));

  logger.debug({ channel }, "WebSocket subscribed to RU channel");
}
```

### 5. Frontend WebSocket Hook Updates

```typescript
// apps/web/src/hooks/websocket.ts

import { useEffect, useCallback } from "react";
import { useWebSocketStore } from "@/stores/websocket";

// RU-specific hooks
export function useFleetEvents(
  onEvent: (event: RUEvent) => void
): void {
  useWebSocketSubscription("fleet:repos", onEvent);
}

export function useSyncEvents(
  sessionId?: string,
  onEvent: (event: RUEvent) => void
): void {
  const channel = sessionId ? `fleet:sync:${sessionId}` : "fleet:sync";
  useWebSocketSubscription(channel, onEvent);
}

export function useSweepEvents(
  sessionId?: string,
  onEvent: (event: RUEvent) => void
): void {
  const channel = sessionId ? `fleet:sweep:${sessionId}` : "fleet:sweep";
  useWebSocketSubscription(channel, onEvent);
}

// Hook for sync progress
export function useSyncProgress(sessionId: string): SyncProgress {
  const [progress, setProgress] = useState<SyncProgress>({
    total: 0,
    completed: 0,
    failed: 0,
    current: undefined,
    operations: [],
  });

  useSyncEvents(sessionId, (event) => {
    switch (event.type) {
      case "ru.sync_repo_started":
        setProgress(p => ({ ...p, current: event.data.fullName }));
        break;
      case "ru.sync_repo_completed":
        setProgress(p => ({
          ...p,
          completed: event.data.completed,
          failed: event.data.failed,
          total: event.data.total,
          current: undefined,
        }));
        break;
      case "ru.sync_completed":
        setProgress(p => ({ ...p, current: undefined }));
        break;
    }
  });

  return progress;
}

// Hook for sweep progress
export function useSweepProgress(sessionId: string): SweepProgress {
  const [progress, setProgress] = useState<SweepProgress>({
    phase: undefined,
    analyzed: 0,
    planned: 0,
    executed: 0,
    failed: 0,
    total: 0,
    current: undefined,
    pendingApprovals: 0,
  });

  useSweepEvents(sessionId, (event) => {
    switch (event.type) {
      case "ru.sweep_progress":
        setProgress(p => ({
          ...p,
          phase: event.data.phase,
          current: event.data.current,
          ...event.data.progress,
        }));
        break;
      case "ru.sweep_plan_created":
        setProgress(p => ({ ...p, pendingApprovals: p.pendingApprovals + 1 }));
        break;
      case "ru.sweep_plan_approved":
      case "ru.sweep_plan_rejected":
        setProgress(p => ({ ...p, pendingApprovals: Math.max(0, p.pendingApprovals - 1) }));
        break;
    }
  });

  return progress;
}
```

